mapper.select:
select s.*,c.name clazzName
from student s left join clazz c on s.clazz_id=c.id


        s.name like concat('%',#{name},'%')


        and s.clazz_id=#{clazzId}


        and s.degree=#{degree}

mapper.update:
update student
set violation_count = violation_count + 1,
    violation_score = violation_score + #{score}
where id = #{id}
